import React, { useState, useRef, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    orange: '#fb923c',
    green: '#a3e635',
  },
  font: "'JetBrains Mono', monospace",
};

// --- Math ---
function gelu(x) {
  return 0.5 * x * (1 + Math.tanh(Math.sqrt(2 / Math.PI) * (x + 0.044715 * Math.pow(x, 3))));
}
function relu(x) {
  return Math.max(0, x);
}
function gatePhi(x) {
  return 0.5 * (1 + Math.tanh(Math.sqrt(2 / Math.PI) * (x + 0.044715 * Math.pow(x, 3))));
}

// --- SVG coordinate config (constants, so safe outside component) ---
const SVG_W = 560;
const SVG_H = 260;
const PAD_L = 44;
const PAD_R = 16;
const PAD_T = 18;
const PAD_B = 36;
const PLOT_W = SVG_W - PAD_L - PAD_R;
const PLOT_H = SVG_H - PAD_T - PAD_B;
const X_MIN = -4, X_MAX = 4;
const Y_MIN = -0.7, Y_MAX = 4.5;

function toSvgX(x) {
  return PAD_L + ((x - X_MIN) / (X_MAX - X_MIN)) * PLOT_W;
}
function toSvgY(y) {
  return PAD_T + ((Y_MAX - y) / (Y_MAX - Y_MIN)) * PLOT_H;
}
function fromSvgX(sx) {
  return ((sx - PAD_L) / PLOT_W) * (X_MAX - X_MIN) + X_MIN;
}

function buildPolyline(fn, steps) {
  const pts = [];
  for (let i = 0; i <= steps; i++) {
    const x = X_MIN + (i / steps) * (X_MAX - X_MIN);
    const y = fn(x);
    const cy = Math.max(Y_MIN, Math.min(Y_MAX, y));
    pts.push(`${toSvgX(x).toFixed(2)},${toSvgY(cy).toFixed(2)}`);
  }
  return pts.join(' ');
}

const GELU_PATH = buildPolyline(gelu, 300);
const RELU_PATH = buildPolyline(relu, 300);

const X_TICKS = [-4, -3, -2, -1, 0, 1, 2, 3, 4];
const Y_TICKS = [0, 1, 2, 3, 4];
const GRID_Y = [-0.5, 0, 0.5, 1, 1.5, 2, 2.5, 3, 3.5, 4];

export default function App() {
  const [inputX, setInputX] = useState(1.0);
  const [showReLU, setShowReLU] = useState(false);
  const svgRef = useRef(null);
  const dragging = useRef(false);

  const currentGelu = gelu(inputX);
  const currentGate = gatePhi(inputX);
  const currentRelu = relu(inputX);

  // Clamped for SVG placement
  const dotSvgX = toSvgX(inputX);
  const dotGeluSvgY = toSvgY(Math.max(Y_MIN, Math.min(Y_MAX, currentGelu)));
  const dotReluSvgY = toSvgY(Math.max(Y_MIN, Math.min(Y_MAX, currentRelu)));

  function updateFromEvent(e) {
    if (!svgRef.current) return;
    const rect = svgRef.current.getBoundingClientRect();
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const relX = (clientX - rect.left) * (SVG_W / rect.width);
    const x = Math.max(X_MIN, Math.min(X_MAX, fromSvgX(relX)));
    setInputX(Math.round(x * 100) / 100);
  }

  function onMouseDown(e) { dragging.current = true; updateFromEvent(e); }
  function onMouseMove(e) { if (dragging.current) updateFromEvent(e); }
  function onMouseUp() { dragging.current = false; }

  // Dynamic insight
  const insight = useMemo(() => {
    const pct = (currentGate * 100).toFixed(1);
    if (inputX <= -2)
      return `x=${inputX.toFixed(2)}: Gate is only ${pct}% open. GeLU softly suppresses (${currentGelu.toFixed(4)}) instead of hard-zeroing like ReLU - gradients can still flow!`;
    if (inputX < 0)
      return `x=${inputX.toFixed(2)}: Gate ${pct}% open. Negative inputs are dampened smoothly - GeLU never fully kills a signal, unlike ReLU's hard cutoff at 0.`;
    if (Math.abs(inputX) < 0.05)
      return `At x=0: Gate is exactly 50% open. GeLU(0) = 0. This midpoint is where the smooth gating is most visible - neither fully on nor off.`;
    if (inputX < 1.5)
      return `x=${inputX.toFixed(2)}: Gate ${pct}% open. Positive inputs mostly pass through. GeLU(x) = ${currentGelu.toFixed(4)} \u2248 x * ${currentGate.toFixed(3)}.`;
    return `x=${inputX.toFixed(2)}: Gate ${pct}% open - nearly linear. For large positives GeLU(x) \u2248 x (${currentGelu.toFixed(4)} vs x=${inputX.toFixed(2)}). Gradients flow freely!`;
  }, [inputX, currentGelu, currentGate]);

  const gateBarColor = inputX >= 0 ? theme.colors.primary : theme.colors.orange;

  return (
    <div style={{
      fontFamily: theme.font,
      background: theme.colors.background,
      minHeight: '100vh',
      color: theme.colors.text,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '12px 16px',
    }}>
      <div style={{ width: '100%', maxWidth: 600 }}>

        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 10 }}>
          <div>
            <div style={{ fontSize: 18, fontWeight: 'bold', color: theme.colors.text, letterSpacing: -0.5 }}>GeLU Activation</div>
            <div style={{ fontSize: 11, color: theme.colors.textSecondary, marginTop: 2 }}>Drag the point along the curve to explore</div>
          </div>
          <button
            onClick={() => setShowReLU(v => !v)}
            style={{
              background: showReLU ? `${theme.colors.orange}22` : theme.colors.surfaceAlt,
              border: `1px solid ${showReLU ? theme.colors.orange : theme.colors.border}`,
              color: showReLU ? theme.colors.orange : theme.colors.textSecondary,
              borderRadius: 6,
              padding: '6px 12px',
              fontSize: 11,
              cursor: 'pointer',
              fontFamily: theme.font,
              whiteSpace: 'nowrap',
              transition: 'all 0.2s ease',
            }}
          >
            {showReLU ? 'Hide ReLU' : 'vs ReLU'}
          </button>
        </div>

        {/* SVG Chart */}
        <div style={{
          background: theme.colors.surface,
          borderRadius: 12,
          border: `1px solid ${theme.colors.border}`,
          overflow: 'hidden',
          boxShadow: '0 4px 20px rgba(0,0,0,0.4)',
        }}>
          <svg
            ref={svgRef}
            width="100%"
            viewBox={`0 0 ${SVG_W} ${SVG_H}`}
            style={{ display: 'block', cursor: 'ew-resize', userSelect: 'none', touchAction: 'none' }}
            onMouseDown={onMouseDown}
            onMouseMove={onMouseMove}
            onMouseUp={onMouseUp}
            onMouseLeave={onMouseUp}
            onTouchStart={e => { dragging.current = true; updateFromEvent(e); }}
            onTouchMove={updateFromEvent}
            onTouchEnd={onMouseUp}
          >
            {/* Background grid */}
            {X_TICKS.map(x => (
              <line key={`gx${x}`}
                x1={toSvgX(x)} y1={PAD_T}
                x2={toSvgX(x)} y2={PAD_T + PLOT_H}
                stroke={x === 0 ? '#444' : '#1e1e1e'} strokeWidth={x === 0 ? 1.5 : 1}
              />
            ))}
            {GRID_Y.map(y => (
              <line key={`gy${y}`}
                x1={PAD_L} y1={toSvgY(y)}
                x2={PAD_L + PLOT_W} y2={toSvgY(y)}
                stroke={y === 0 ? '#444' : '#1a1a1a'} strokeWidth={y === 0 ? 1.5 : 1}
              />
            ))}

            {/* X axis tick labels */}
            {[-4, -2, 0, 2, 4].map(x => (
              <text key={`xl${x}`}
                x={toSvgX(x)} y={PAD_T + PLOT_H + 18}
                textAnchor="middle" fontSize={10} fill={theme.colors.textSecondary}>{x}
              </text>
            ))}

            {/* Y axis tick labels */}
            {Y_TICKS.map(y => (
              <text key={`yl${y}`}
                x={PAD_L - 8} y={toSvgY(y) + 4}
                textAnchor="end" fontSize={10} fill={theme.colors.textSecondary}>{y}
              </text>
            ))}

            {/* Axis labels */}
            <text x={PAD_L + PLOT_W - 6} y={toSvgY(0) + 14} fontSize={10} fill={theme.colors.textSecondary}>x</text>
            <text x={PAD_L - 6} y={PAD_T - 4} fontSize={10} fill={theme.colors.textSecondary}>y</text>

            {/* Dashed crosshairs */}
            <line
              x1={dotSvgX} y1={PAD_T}
              x2={dotSvgX} y2={dotGeluSvgY}
              stroke={theme.colors.primary} strokeWidth={1} strokeDasharray="4,4" opacity={0.45}
            />
            <line
              x1={PAD_L} y1={dotGeluSvgY}
              x2={dotSvgX} y2={dotGeluSvgY}
              stroke={theme.colors.primary} strokeWidth={1} strokeDasharray="4,4" opacity={0.45}
            />

            {/* x annotation on axis */}
            <rect x={dotSvgX - 14} y={PAD_T + PLOT_H + 4} width={28} height={14} rx={3}
              fill={`${theme.colors.primary}33`} />
            <text x={dotSvgX} y={PAD_T + PLOT_H + 14}
              textAnchor="middle" fontSize={9} fill={theme.colors.primary} fontWeight="bold">
              {inputX.toFixed(2)}
            </text>

            {/* ReLU curve */}
            {showReLU && (
              <polyline
                points={RELU_PATH}
                fill="none"
                stroke={theme.colors.orange}
                strokeWidth={2}
                opacity={0.55}
                strokeLinejoin="round"
              />
            )}

            {/* GeLU curve */}
            <polyline
              points={GELU_PATH}
              fill="none"
              stroke={theme.colors.primary}
              strokeWidth={2.5}
              strokeLinejoin="round"
            />

            {/* ReLU dot */}
            {showReLU && (
              <circle
                cx={dotSvgX}
                cy={dotReluSvgY}
                r={5}
                fill={theme.colors.orange}
                opacity={0.75}
                stroke="rgba(0,0,0,0.4)"
                strokeWidth={1}
              />
            )}

            {/* GeLU draggable dot */}
            <circle
              cx={dotSvgX}
              cy={dotGeluSvgY}
              r={9}
              fill={theme.colors.primary}
              stroke={theme.colors.text}
              strokeWidth={2}
              style={{ filter: 'drop-shadow(0 0 6px rgba(139,92,246,0.7))' }}
            />

            {/* Legend */}
            <circle cx={PAD_L + 10} cy={PAD_T + 10} r={4} fill={theme.colors.primary} />
            <text x={PAD_L + 19} y={PAD_T + 14} fontSize={10} fill={theme.colors.textSecondary}>GeLU</text>
            {showReLU && (
              <>
                <circle cx={PAD_L + 60} cy={PAD_T + 10} r={4} fill={theme.colors.orange} opacity={0.75} />
                <text x={PAD_L + 69} y={PAD_T + 14} fontSize={10} fill={theme.colors.textSecondary}>ReLU</text>
              </>
            )}
          </svg>

          {/* Stats row */}
          <div style={{
            display: 'flex',
            justifyContent: 'space-around',
            padding: '10px 12px',
            borderTop: `1px solid ${theme.colors.border}`,
            background: theme.colors.surfaceAlt,
            gap: 8,
          }}>
            <div style={{ textAlign: 'center', flex: 1 }}>
              <div style={{ fontSize: 9, color: theme.colors.textSecondary, marginBottom: 3, letterSpacing: 0.5 }}>INPUT x</div>
              <div style={{ fontSize: 20, fontWeight: 'bold', color: theme.colors.blue, transition: 'color 0.2s' }}>
                {inputX.toFixed(2)}
              </div>
            </div>

            <div style={{ width: 1, background: theme.colors.border, margin: '4px 0' }} />

            <div style={{ textAlign: 'center', flex: 1 }}>
              <div style={{ fontSize: 9, color: theme.colors.textSecondary, marginBottom: 3, letterSpacing: 0.5 }}>GATE Phi(x)</div>
              <div style={{ fontSize: 20, fontWeight: 'bold', color: theme.colors.yellow, transition: 'color 0.2s' }}>
                {currentGate.toFixed(3)}
              </div>
              <div style={{ fontSize: 9, color: theme.colors.textMuted }}>
                {(currentGate * 100).toFixed(1)}% open
              </div>
            </div>

            <div style={{ width: 1, background: theme.colors.border, margin: '4px 0' }} />

            <div style={{ textAlign: 'center', flex: 1 }}>
              <div style={{ fontSize: 9, color: theme.colors.textSecondary, marginBottom: 3, letterSpacing: 0.5 }}>GeLU(x)</div>
              <div style={{ fontSize: 20, fontWeight: 'bold', color: theme.colors.primary, transition: 'color 0.2s' }}>
                {currentGelu.toFixed(4)}
              </div>
            </div>

            {showReLU && (
              <>
                <div style={{ width: 1, background: theme.colors.border, margin: '4px 0' }} />
                <div style={{ textAlign: 'center', flex: 1 }}>
                  <div style={{ fontSize: 9, color: theme.colors.textSecondary, marginBottom: 3, letterSpacing: 0.5 }}>ReLU(x)</div>
                  <div style={{ fontSize: 20, fontWeight: 'bold', color: theme.colors.orange, transition: 'color 0.2s' }}>
                    {currentRelu.toFixed(4)}
                  </div>
                </div>
              </>
            )}
          </div>
        </div>

        {/* Gating bar */}
        <div style={{
          marginTop: 8,
          background: theme.colors.surface,
          borderRadius: 8,
          border: `1px solid ${theme.colors.border}`,
          padding: '10px 14px',
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
            <div style={{ fontSize: 10, color: theme.colors.textSecondary }}>
              SOFT GATE: GeLU(x) = x * Phi(x) = {inputX.toFixed(2)} * {currentGate.toFixed(3)} = {currentGelu.toFixed(4)}
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <div style={{ flex: 1, height: 10, background: theme.colors.surfaceAlt, borderRadius: 5, overflow: 'hidden' }}>
              <div style={{
                width: `${Math.round(currentGate * 1000) / 10}%`,
                height: '100%',
                background: gateBarColor,
                borderRadius: 5,
                transition: 'width 0.08s ease, background 0.2s ease',
                boxShadow: `0 0 8px ${gateBarColor}66`,
              }} />
            </div>
            <div style={{ fontSize: 11, color: theme.colors.textSecondary, minWidth: 44, textAlign: 'right' }}>
              {(currentGate * 100).toFixed(1)}%
            </div>
          </div>
        </div>

        {/* Dynamic insight */}
        <div style={{
          marginTop: 8,
          padding: '10px 14px',
          background: theme.colors.surfaceAlt,
          borderRadius: 8,
          fontSize: 11,
          color: theme.colors.textSecondary,
          borderLeft: `3px solid ${theme.colors.primary}`,
          lineHeight: 1.6,
          transition: 'border-color 0.3s',
        }}>
          {insight}
        </div>

        {/* Formula reminder */}
        <div style={{
          marginTop: 8,
          padding: '8px 14px',
          background: theme.colors.surface,
          borderRadius: 8,
          border: `1px solid ${theme.colors.border}`,
          fontSize: 10,
          color: theme.colors.textMuted,
          textAlign: 'center',
          letterSpacing: 0.3,
        }}>
          GeLU(x) = 0.5 * x * (1 + tanh(sqrt(2/pi) * (x + 0.044715 * x^3)))
        </div>

      </div>
    </div>
  );
}
